INSERT INTO products (name, category, short_description, long_description, price, image_url, stock_quantity, weight, colour, use_case, rating, featured) VALUES ('Gym Rat 10.2mm Rope', 'ropes', 'Burly 35m gym rope built to survive endless top-rope laps.', 'A thick, hard-wearing 10.2mm sheath laughs off the wear of indoor lowering and auto-belay abuse. The 35m length is perfect for most walls, and the high-vis colour is easy to flake under gym lights.', 109.00, '/images/products/gym-rat-102mm-rope.webp', 34, 4600, 'Volt Yellow', 'indoor', 4.5, FALSE)
