INSERT INTO products (name, category, short_description, long_description, price, image_url, stock_quantity, weight, colour, use_case, rating, featured) VALUES ('WireGate Quickdraw Set', 'carabiners', 'Six wiregate quickdraws — light, snag-free, ready to send.', 'Wiregate carabiners cut weight and resist gate-flutter on hard clips. This set of six comes with grippy 12cm dogbones and a colour-coded bolt-end biner so you always clip the rope the right way.', 74.00, '/images/products/wiregate-quickdraw-set.webp', 40, 570, 'Mixed Anodised', 'sport', 4.8, FALSE)
