INSERT INTO products (name, category, short_description, long_description, price, image_url, stock_quantity, weight, colour, use_case, rating, featured) VALUES ('BombProof HMS Screwgate', 'carabiners', 'Big, burly pear locker for guide-mode belays and rescue rigs.', 'A large basket and high cross-section make the BombProof ideal for Munter hitches, guide-mode belays, and any time you want a locker you can grab with gloves on. Built to outlast the route.', 21.50, '/images/products/bombproof-hms-screwgate.webp', 76, 82, 'Steel Blue', 'alpine', 4.7, FALSE)
